DROP TABLE IF EXISTS `ap_forms`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `ap_forms` (
  `form_id` int(11) NOT NULL AUTO_INCREMENT,
  `logic_permission_enable` tinyint(1) DEFAULT 0,
  `logic_workflow_enable` tinyint(1) DEFAULT 0,
  `form_name` text DEFAULT NULL,
  `form_description` text DEFAULT NULL,
  `form_email` varchar(255) DEFAULT NULL,
  `form_redirect` text DEFAULT NULL,
  `form_success_message` text DEFAULT NULL,
