INSERT INTO `invoicetemplates` VALUES (4,'Building Permit Invoice',25952,5,'<table width=\"100%\">\r\n	<tbody>\r\n		<tr>\r\n			<td width=\"25%\"><img alt=\"coatofarms\" src=\"/assets_backend/img_kajiado/coatofarms.jpg\" style=\" width:100px; text-align:center\" /></td>\r\n			<td style=\"text-align:center\" width=\"50%\">\r\n			<h1><b>COUNTY GOVERNMENT OF NAKURU</b></h1>\r\n\r\n			<h2>BUILDING PERMIT INVOICE {inv_status}</h2>\r\n			</td>\r\n			<td width=\"25%\"><img alt=\"logo\" src=\"/assets_unified/images/nakuru.png\" style=\" width:100px; text-align:center\" /></td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<hr />\r\n<p>NAME OF APPLICANT: <span font-size:=\"\" lucida=\"\" sans=\"\" style=\"color: rgb(99, 110, 123); font-family: LatoRegular, \">{sf_fullname}</span></p>\r\n\r\n<p>ADDRESS OF APPLICANT:&nbsp;<span font-size:=\"\" lucida=\"\" sans=\"\" style=\"color: rgb(99, 110, 123); font-family: LatoRegular, \">{fm_element_3}</span></p>\r\n\r\n<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>MOBILE NO: <span font-size:=\"\" lucida=\"\" sans=\"\" style=\"color: rgb(99, 110, 123); font-family: LatoRegular, \">{fm_element_13}</span></td>\r\n			<td style=\"text-align:right\">&nbsp;EMAIL: <span font-size:=\"\" lucida=\"\" sans=\"\" style=\"color: rgb(99, 110, 123); font-family: LatoRegular, \">{fm_element_13}</span></td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>INVOICE NUMBER: <strong>{inv_no}</strong></p>\r\n{inv_fee_table}\r\n\r\n<table>\r\n	<tbody>\r\n		<tr>\r\n			<td><b>TOTAL (KES)</b></td>\r\n			<td style=\"text-align:right\"><b>{inv_total}</b></td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n&nbsp;\r\n\r\n<table width=\"100%\">\r\n	<tbody>\r\n		<tr>\r\n			<td>SIGNATURE:</td>\r\n			<td>&nbsp;</td>\r\n			<td style=\"text-align:right\">DATE: {inv_date_created}</td>\r\n		</tr>\r\n		<tr>\r\n			<td width=\"40%\"><b>{qr_code_small}</b></td>\r\n			<td width=\"20%\">&nbsp;</td>\r\n			<td style=\"text-align:right\" width=\"40%\"><b>County Director of Revenue</b><br />\r\n			Account 